class AccountInfo:
    def __init__(self, first_name, last_name, email, phone, city):
        self.first_name = first_name
        self.last_name = last_name
        self.email = email
        self.phone = phone
        self.city = city


def create_account(info):
    return {'name': info.first_name + ' ' + info.last_name, 'email': info.email, 'phone': info.phone, 'city': info.city}

class ShippingDetails:
    def __init__(self, name, street, city, country, postal_code):
        self.name = name
        self.street = street
        self.city = city
        self.country = country
        self.postal_code = postal_code


def ship(details):
    return f'{details.name}-{details.street}-{details.city}-{details.country}-{details.postal_code}'

class ReservationRequest:
    def __init__(self, first_name, last_name, seat, gate, flight_code):
        self.first_name = first_name
        self.last_name = last_name
        self.seat = seat
        self.gate = gate
        self.flight_code = flight_code


def reserve(request):
    return f'{request.first_name} {request.last_name}:{request.seat}:{request.gate}:{request.flight_code}'

class NoticeTarget:
    def __init__(self, name, email, phone, channel, template):
        self.name = name
        self.email = email
        self.phone = phone
        self.channel = channel
        self.template = template


def send_notice(target):
    return f'{target.name}:{target.email}:{target.phone}:{target.channel}:{target.template}'
